import React, { useState } from 'react';

interface Photo {
  id: number;
  src: string;
  caption: string;
  color: string;
  label: string;
}

const photos: Photo[] = [
  {
    id: 1,
    src: '/img/image1.png',
    caption: 'Ring Ceremony',
    color: 'from-rose-900 to-red-950',
    label: 'The Promise',
  },
  {
    id: 2,
    src: '/img/image2.png',
    caption: 'Mehendi Night',
    color: 'from-emerald-900 to-green-950',
    label: 'Henna Night',
  },
  {
    id: 3,
    src: '/img/image3.jpeg',
    caption: 'Haldi Ceremony',
    color: 'from-yellow-800 to-amber-950',
    label: 'Turmeric Glow',
  },
  {
    id: 4,
    src: '/img/image4.jpeg',
    caption: 'Temple Blessing',
    color: 'from-orange-900 to-red-950',
    label: 'Sacred Moments',
  },
  {
    id: 5,
    src: '/img/image5.jpeg',
    caption: 'Bridal Look',
    color: 'from-pink-900 to-rose-950',
    label: 'The Bride',
  },
];

const PhotoGallery: React.FC = () => {
  const [lightbox, setLightbox] = useState<Photo | null>(null);

  return (
    <section
      id="gallery"
      style={{
        minHeight: '100vh',
        background:
          'linear-gradient(180deg, #050205 0%, #1a0508 30%, #2a0810 60%, #1a0508 80%, #050205 100%)',
        padding: '80px 20px',
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* Background pattern */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          backgroundImage: `radial-gradient(circle at 20% 50%, rgba(180,30,0,0.08) 0%, transparent 50%),
                            radial-gradient(circle at 80% 20%, rgba(255,107,53,0.06) 0%, transparent 40%)`,
          pointerEvents: 'none',
        }}
      />

      <div style={{ maxWidth: 1100, margin: '0 auto', position: 'relative' }}>
        {/* Title */}
        <div style={{ textAlign: 'center', marginBottom: 60 }}>
          <div
            style={{
              fontFamily: "'Noto Serif Tamil', serif",
              fontSize: 12,
              color: '#FFA07A',
              letterSpacing: '0.3em',
              marginBottom: 8,
            }}
          >
            நினைவுகள்
          </div>
          <h2
            style={{
              fontFamily: "'Cormorant Garamond', serif",
              fontSize: 'clamp(2rem, 6vw, 3.5rem)',
              color: '#FFD700',
              fontStyle: 'italic',
              fontWeight: 300,
              margin: '0 0 16px',
              letterSpacing: '0.05em',
            }}
          >
            Our Gallery
          </h2>
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 16,
              justifyContent: 'center',
            }}
          >
            <div
              style={{
                flex: 1,
                maxWidth: 120,
                height: 1,
                background: 'linear-gradient(90deg, transparent, #FFD700)',
              }}
            />
            <span style={{ color: '#FFD700', fontSize: 18 }}>✦</span>
            <div
              style={{
                flex: 1,
                maxWidth: 120,
                height: 1,
                background: 'linear-gradient(90deg, #FFD700, transparent)',
              }}
            />
          </div>
        </div>

        {/* Gallery grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns:
              'repeat(auto-fill, minmax(min(280px, 100%), 1fr))',
            gap: 20,
          }}
        >
          {photos.map((photo, idx) => (
            <div
              key={photo.id}
              onClick={() => setLightbox(photo)}
              style={{
                aspectRatio: idx === 0 || idx === 4 ? '16/9' : '4/3',
                gridColumn: idx === 0 ? 'span 2' : 'span 1',
                background: `linear-gradient(145deg, ${getColor(photo.color)})`,
                border: '1px solid rgba(255,215,0,0.2)',
                borderRadius: 8,
                cursor: 'pointer',
                position: 'relative',
                overflow: 'hidden',
                transition: 'all 0.3s ease',
                boxShadow: '0 4px 20px rgba(0,0,0,0.4)',
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform =
                  'translateY(-6px) scale(1.02)';
                e.currentTarget.style.border =
                  '1px solid rgba(255,215,0,0.6)';
                e.currentTarget.style.boxShadow =
                  '0 12px 40px rgba(255,107,53,0.3)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform =
                  'translateY(0) scale(1)';
                e.currentTarget.style.border =
                  '1px solid rgba(255,215,0,0.2)';
                e.currentTarget.style.boxShadow =
                  '0 4px 20px rgba(0,0,0,0.4)';
              }}
            >
              {/* Image */}
              <img
                src={photo.src}
                alt={photo.caption}
                style={{
                  position: 'absolute',
                  inset: 2,
                  width: '100%',
                  height: '100%',
                  objectFit: 'cover',
                }}
              />

              {/* Gradient overlay */}
              <div
                style={{
                  position: 'absolute',
                  inset: 0,
                  background:
                    'linear-gradient(180deg, transparent 40%, rgba(0,0,0,0.75) 100%)',
                }}
              />

              {/* Bottom label */}
              <div
                style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  right: 0,
                  padding: '12px 16px',
                }}
              >
                <div
                  style={{
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: 'clamp(1rem, 2.5vw, 1.3rem)',
                    color: '#FFD700',
                    fontStyle: 'italic',
                  }}
                >
                  {photo.label}
                </div>
                <div
                  style={{
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: 11,
                    color: 'rgba(255,160,122,0.8)',
                    letterSpacing: '0.2em',
                  }}
                >
                  {photo.caption.toUpperCase()}
                </div>
              </div>

              {/* Hover icon */}
              <div
                style={{
                  position: 'absolute',
                  top: '50%',
                  left: '50%',
                  transform: 'translate(-50%, -50%)',
                  width: 48,
                  height: 48,
                  borderRadius: '50%',
                  background: 'rgba(255,215,0,0.15)',
                  border: '1.5px solid rgba(255,215,0,0.4)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  opacity: 0,
                  transition: 'opacity 0.3s',
                  fontSize: 20,
                }}
                className="zoom-icon"
              >
                🔍
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div
          onClick={() => setLightbox(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.92)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9998,
            backdropFilter: 'blur(8px)',
          }}
        >
          <div
            style={{
              background: `linear-gradient(145deg, ${getColor(
                lightbox.color
              )})`,
              border: '1.5px solid rgba(255,215,0,0.4)',
              borderRadius: 12,
              padding: '40px',
              textAlign: 'center',
              maxWidth: 600,
              width: '90vw',
              boxShadow: '0 0 80px rgba(255,107,53,0.3)',
            }}
          >
            <img
              src={lightbox.src}
              alt={lightbox.caption}
              style={{
                width: '100%',
                maxHeight: 320,
                objectFit: 'fit',
                borderRadius: 8,
                marginBottom: 24,
              }}
            />
            <div
              style={{
                fontFamily: "'Cormorant Garamond', serif",
                fontSize: '2.2rem',
                color: '#FFD700',
                fontStyle: 'italic',
                marginBottom: 6,
              }}
            >
              {lightbox.label}
            </div>
            <div
              style={{
                fontFamily: "'Noto Serif Tamil', serif",
                fontSize: 13,
                color: '#FFA07A',
                letterSpacing: '0.2em',
              }}
            >
              {lightbox.caption}
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

function getColor(colorClass: string): string {
  const map: { [key: string]: string } = {
    'from-rose-900 to-red-950': '#4a0d1a, #2d0510',
    'from-emerald-900 to-green-950': '#4a0d1a, #02d0510',
    'from-yellow-800 to-amber-950': '#4a3006, #2d1a02',
    'from-orange-900 to-red-950': '#4a1e06, #2d0a02',
    'from-pink-900 to-rose-950': '#4a0d25, #2d0515',
  };
  return map[colorClass] || '#4a0d1a, #2d0510';
}

export default PhotoGallery;
